mapper.select:
SELECT * FROM ( SELECT R.CO_ID as CO_ID, R.RPT_ID as RPT_ID, R.RPT_CD as RPT_CD, R.RPT_NM as RPT_NM, R.RPT_URL as RPT_URL, R.RPT_FILE_ID as RPT_FILE_ID, F.FILE_NM as RPT_FILE_NAME, R.PGM_ID as PGM_ID, P.PGM_NM as PGM_NM, R.USE_FLG as USE_FLG, R.CRE_USR_ID as CRE_USR_ID, R.CRE_DT as CRE_DT, R.UPD_USR_ID as UPD_USR_ID, R.UPD_DT as UPD_DT FROM COM_RPT_STUP R LEFT JOIN COM_FILE F ON R.RPT_FILE_ID = F.FILE_ID AND R.CO_ID = F.CO_ID LEFT JOIN COM_PGM P ON R.PGM_ID = P.PGM_ID AND R.CO_ID = P.CO_ID WHERE 1=1
AND R.USE_FLG = #{useFlg}
AND R.CO_ID = #{coId}
AND R.RPT_ID = #{rptId}
AND R.RPT_CD = #{rptCd}
AND R.PGM_ID = #{pgmId}
AND P.PGM_CD = #{pgmCd}
AND ( R.RPT_NM ILIKE '%' || #{textSearch} || '%' OR R.RPT_CD ILIKE '%' || #{textSearch} || '%' )
ORDER BY R.RPT_CD ${sort.sortType}, R.UPD_DT DESC
ORDER BY R.RPT_NM ${sort.sortType}, R.UPD_DT DESC
ORDER BY R.USE_FLG ${sort.sortType}, R.UPD_DT DESC
ORDER BY R.UPD_DT DESC
) AS R_LIST WHERE 1=1
LIMIT #{pagination.pageSize} OFFSET (#{pagination.current} - 1) * #{pagination.pageSize}

SELECT COUNT(*)
FROM COM_RPT_STUP R
LEFT JOIN COM_PGM P ON R.PGM_ID = P.PGM_ID AND R.CO_ID = P.CO_ID
WHERE 1=1

        AND R.USE_FLG = #{useFlg}


        AND R.CO_ID = #{coId}


        AND R.RPT_ID = #{rptId}


        AND R.RPT_CD = #{rptCd}


        AND R.PGM_ID = #{pgmId}


        AND P.PGM_CD = #{pgmCd}


        AND (
            R.RPT_NM ILIKE '%' || #{textSearch} || '%'
            OR R.RPT_CD ILIKE '%' || #{textSearch} || '%'
        )

SELECT R.CO_ID as CO_ID, R.RPT_ID as RPT_ID, R.RPT_CD as RPT_CD, R.RPT_NM as RPT_NM, R.RPT_URL as RPT_URL, R.RPT_FILE_ID as RPT_FILE_ID, F.FILE_NM as RPT_FILE_NAME, R.PGM_ID as PGM_ID, P.PGM_NM as PGM_NM, R.USE_FLG as USE_FLG, R.CRE_USR_ID as CRE_USR_ID, R.CRE_DT as CRE_DT, R.UPD_USR_ID as UPD_USR_ID, R.UPD_DT as UPD_DT FROM COM_RPT_STUP R LEFT JOIN COM_PGM P ON R.PGM_ID = P.PGM_ID AND R.CO_ID = P.CO_ID LEFT JOIN COM_FILE F ON R.RPT_FILE_ID = F.FILE_ID AND R.CO_ID = F.CO_ID WHERE 1=1
AND R.CO_ID = #{coId}
AND R.RPT_ID = #{rptId}
AND R.RPT_CD = #{rptCd}
LIMIT 1

SELECT COUNT(1)
FROM COM_RPT_STUP R
WHERE 1=1
    AND R.CO_ID = #{coId}

        AND R.RPT_ID != #{rptId}


        AND R.RPT_CD = #{rptCd}

